# Helper for structured writing of values into a RustBuffer.
class RustBufferBuilder
  def initialize
    @rust_buf = RustBuffer.alloc 16
    @rust_buf.len = 0
  end

  def finalize
    rbuf = @rust_buf

    @rust_buf = nil

    rbuf
  end

  def discard
    return if @rust_buf.nil?

    rbuf = finalize
    rbuf.free
  end

  def write(value)
    reserve(value.bytes.size) do
      @rust_buf.data.put_array_of_char @rust_buf.len, value.bytes
    end
  end

  def write_u16(v)
    v = ::CyclopsSdkSchema::uniffi_in_range(v, "u16", 0, 2**16)
    pack_into(2, 'S>', v)
  end

  def write_u32(v)
    v = ::CyclopsSdkSchema::uniffi_in_range(v, "u32", 0, 2**32)
    pack_into(4, 'L>', v)
  end

  def write_u64(v)
    v = ::CyclopsSdkSchema::uniffi_in_range(v, "u64", 0, 2**64)
    pack_into(8, 'Q>', v)
  end

  def write_bool(v)
    pack_into(1, 'c', v ? 1 : 0)
  end

  def write_string(v)
    v = ::CyclopsSdkSchema::uniffi_utf8(v)
    pack_into 4, 'l>', v.bytes.size
    write v
  end

  # The Object type PreservedJson.

  def write_TypePreservedJson(obj)
    handle = PreservedJson.uniffi_lower obj
    pack_into(8, 'Q>', handle)
  end

  # The Record type ClaimLifecycle.

  def write_TypeClaimLifecycle(v)
    self.write_Optionalstring(v.shutdown_time)
    self.write_Optionalstring(v.shutdown_policy)
    self.write_Optionalbool(v.auto_renew)
  end

  # The Record type ClaimSpec.

  def write_TypeClaimSpec(v)
    self.write_TypeSandboxTemplateRef(v.sandbox_template_ref)
    self.write_Optionalstring(v.warmpool)
    self.write_Optionalu32(v.bind_deadline)
    self.write_OptionalTypeClaimLifecycle(v.lifecycle)
  end

  # The Record type OSGymSandboxClaimCondition.

  def write_TypeOSGymSandboxClaimCondition(v)
    self.write_Optionalstring(v.type)
    self.write_Optionalstring(v.status)
    self.write_Optionalstring(v.reason)
    self.write_Optionalstring(v.message)
