      raise TypeError.new "Expected a PreservedJson instance, got #{inst}"
    end
  end

  def uniffi_clone_handle()
    return ::CyclopsSdkSchema.rust_call(
      :uniffi_cyclops_sdk_schema_fn_clone_preservedjson,
